from itertools import product

class Solution:
    def makeParityAlternating(self, nums):
        # Independent approach: literally try every combination of leaving each
        # element unchanged, +1, or -1 (only feasible for the small literal
        # inputs this oracle is checked against), keep only combinations that
        # end up parity alternating, and pick the cheapest / then smallest range.
        n = len(nums)
        best = None
        for deltas in product((-1, 0, 1), repeat=n):
            arr = [nums[i] + deltas[i] for i in range(n)]
            ok = True
            for i in range(n - 1):
                if (arr[i] % 2) == (arr[i + 1] % 2):
                    ok = False
                    break
            if not ok:
                continue
            cost = sum(1 for d in deltas if d != 0)
            rng = max(arr) - min(arr)
            if best is None or (cost, rng) < best:
                best = (cost, rng)
        return [best[0], best[1]]

