class Solution:
    def makeParityAlternating(self, nums):
        def best_for_pattern(start_parity):
            fixed = []
            adjustable = []
            for i, v in enumerate(nums):
                want = (start_parity + i) % 2
                if v % 2 == want:
                    fixed.append(v)
                else:
                    adjustable.append(v)
            mismatches = len(adjustable)
            if not adjustable:
                rng = (max(fixed) - min(fixed)) if fixed else 0
                return mismatches, rng
            adjustable.sort()
            m = len(adjustable)
            base_min = min(fixed) if fixed else None
            base_max = max(fixed) if fixed else None
            best_range = None
            for i in range(m + 1):
                mins = []
                maxs = []
                if i > 0:
                    mins.append(adjustable[0] + 1)
                    maxs.append(adjustable[i - 1] + 1)
                if i < m:
                    mins.append(adjustable[i] - 1)
                    maxs.append(adjustable[m - 1] - 1)
                if base_min is not None:
                    mins.append(base_min)
                    maxs.append(base_max)
                rng = max(maxs) - min(mins)
                if best_range is None or rng < best_range:
                    best_range = rng
            return mismatches, best_range

        m0, r0 = best_for_pattern(0)
        m1, r1 = best_for_pattern(1)
        min_ops = min(m0, m1)
        candidates = []
        if m0 == min_ops:
            candidates.append(r0)
        if m1 == min_ops:
            candidates.append(r1)
        return [min_ops, min(candidates)]

