var makeParityAlternating = function(nums) {
    function parity(v) {
        return ((v % 2) + 2) % 2;
    }
    function arrMin(arr) {
        let m = arr[0];
        for (let i = 1; i < arr.length; i++) if (arr[i] < m) m = arr[i];
        return m;
    }
    function arrMax(arr) {
        let m = arr[0];
        for (let i = 1; i < arr.length; i++) if (arr[i] > m) m = arr[i];
        return m;
    }
    function bestForPattern(startParity) {
        const fixed = [];
        const adjustable = [];
        for (let i = 0; i < nums.length; i++) {
            const v = nums[i];
            const want = (startParity + i) % 2;
            if (parity(v) === want) fixed.push(v);
            else adjustable.push(v);
        }
        const mismatches = adjustable.length;
        if (adjustable.length === 0) {
            const rng = fixed.length ? arrMax(fixed) - arrMin(fixed) : 0;
            return [mismatches, rng];
        }
        adjustable.sort((a, b) => a - b);
        const m = adjustable.length;
        const hasFixed = fixed.length > 0;
        const baseMin = hasFixed ? arrMin(fixed) : null;
        const baseMax = hasFixed ? arrMax(fixed) : null;
        let bestRange = null;
        for (let i = 0; i <= m; i++) {
            const mins = [];
            const maxs = [];
            if (i > 0) {
                mins.push(adjustable[0] + 1);
                maxs.push(adjustable[i - 1] + 1);
            }
            if (i < m) {
                mins.push(adjustable[i] - 1);
                maxs.push(adjustable[m - 1] - 1);
            }
            if (hasFixed) {
                mins.push(baseMin);
                maxs.push(baseMax);
            }
            const rng = arrMax(maxs) - arrMin(mins);
            if (bestRange === null || rng < bestRange) bestRange = rng;
        }
        return [mismatches, bestRange];
    }

    const [m0, r0] = bestForPattern(0);
    const [m1, r1] = bestForPattern(1);
    const minOps = Math.min(m0, m1);
    const candidates = [];
    if (m0 === minOps) candidates.push(r0);
    if (m1 === minOps) candidates.push(r1);
    return [minOps, arrMin(candidates)];
};
